var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"후후, 어울리나요?","JPN":"ふふ、似合っていますか？","ENG":"Hehe, how does it look?","TWN":"呵呵，合適嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"내가 보는 눈이 좀 있지. 아주 잘 어울려.","JPN":"妾の目に狂いはない。よく似合っているぞ。","ENG":"It looks great. And you can take my word for it.","TWN":"我的眼光不會錯的，一定很適合她。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유. 다 갈아 입었니?","JPN":"千冬。着替え終わったの？","ENG":"Chifuyu, are you done changing?","TWN":"千冬，你換好了嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"어머.","JPN":"あら。","ENG":"Oh my.","TWN":"哇……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"},"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우와아……","JPN":"うわあ……","ENG":"Wow...","TWN":"哇……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"},"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"대, 대단한데, 이 손님?","JPN":"お、お客さん、すごいよ。","ENG":"Th-this customer looks amazing!","TWN":"這會客人，厲害喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"손님 정말 예뻐요!","JPN":"お客さん、本当にキレイです！","ENG":"You look beautiful!","TWN":"客人好漂亮！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"이건……","JPN":"これは……","ENG":"This is...","TWN":"這件衣服……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"통기성이 아주 좋은 옷이군요.","JPN":"とても通気性に優れた服ですね。","ENG":"A very breathable fabric.","TWN":"非常透氣呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"게다가…… 묘하게 몸이 식는 기분입니다.","JPN":"それに……妙に体が冷めるような気がします。","ENG":"And... it seems to cool my body as well.","TWN":"而且…有種涼感的感覺。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그렇지? 옷에 특별한 마법을 부여해서 열을 조절할 수 있을 거야.","JPN":"だろう？　服に特別な魔法を加えたから、熱を調節できるはずだ。","ENG":"Yeah? I put a spell on the outfit, so it should help you moderate your temperature.","TWN":"對吧？衣服上有特殊的魔法，可以調節溫度。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아까 우리가 잡은 녀석한테서 나온 재료가 핵심이었어.","JPN":"さっき妾たちがやっつけた奴から出た材料が効いている。","ENG":"The material we got from that C.O. was key.","TWN":"剛才我們逮到的那個傢伙身上的材料是關鍵。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"감사합니다. 이 은혜를 어떻게 갚아야 할지……","JPN":"ありがとうございます。どうお礼をしたらいいか……","ENG":"Thank you. I do not know how I can repay you...","TWN":"謝謝你，我不知道該如何報答這份恩情……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"됐어. 내가 그냥 만들어주고 싶었던 옷이었으니까.","JPN":"お礼はいい。ただこの服を妾が作ってみたかっただけだから。","ENG":"It's fine. I just wanted to make one for you.","TWN":"不用，是我自己想做給你的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머?","JPN":"あら？","ENG":"Oh?","TWN":"喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그러니까…… 크흠. 카페 차원에서 협찬한 걸로 치자고","JPN":"だから……コホン。カフェが提供したことにしようではないか。","ENG":"I mean... Ahem. Let's just say we're sponsoring you.","TWN":"所以……咳咳，就當作是咖啡廳贊助你的吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"의상이 아주 만족스러웠나 봐, 라우라?","JPN":"衣装がとても気に入ったのね、ラウラ。","ENG":"Sounds like you're really happy with the outfit, Laura.","TWN":"蘿拉，看來你對這件衣服很滿意喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"당연한 소리를 가지고 자꾸 그럴래?","JPN":"当たり前のことを何度も言うな。","ENG":"Are you going to continue stating the obvious?","TWN":"可以不要一直說廢話嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"옆에서 계속 초 칠 거면 너도 얼른 가서 손님들 주문이나 받아.","JPN":"隣でずっと水をさすつもりなら、汝も早く行ってお客さんの接待でもしろ。","ENG":"Go join the others and take orders instead of ruining the mood.","TWN":"要是你再說這些有的沒的，那你也去替客人點餐吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"손님들, 축제에 간댔지?","JPN":"汝たち、お祭りに行くのだろう？","ENG":"You said you were going to the festival, right?","TWN":"你們是要去參加活動對吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"장담하건대, 손님들이 그 축제에서 제일 주목받는 사람들일 거야.","JPN":"妾が保障する。汝らがそのお祭りで一番注目を浴びるだろう。","ENG":"I can guarantee that you two will be the belles of the ball.","TWN":"我敢保證，你們一定會成為活動裡最耀眼的人。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"사람들이 옷에 관심을 보이면 카페 홍보나 좀 부탁해.","JPN":"服に興味がありそうな人にカフェの宣伝をよろしく頼む。","ENG":"If people are interested in the outfit, help promote the cafe.","TWN":"要是有人對這件衣服有興趣，你們就幫我們宣傳一下咖啡廳。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그게 내가 당신들한테 받는 대가야.","JPN":"それが汝らが妾に払う代価だ。","ENG":"That's the price of the costume.","TWN":"這就是我的報酬。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"감사합니다. 라우라 님.","JPN":"ありがとうございます、ラウラ様。","ENG":"Thank you, Miss Laura.","TWN":"謝謝你，蘿拉。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"}}}},{"id":"L44_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"꼬마 무녀님이랑 호위 동생. 즐거웠어~","JPN":"ちびっ子巫女さんと護衛の妹さん。楽しかったわ～","ENG":"It was nice meeting you, little priestess, and her bodyguard sister!","TWN":"小女巫和她的護衛妹妹，很開心認識你們～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"}}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"꼬마 무녀가 아니라…… 아닙니다. 즐거웠습니다.","JPN":"ちびっ子巫女ではなくて……いいえ。楽しかったです。","ENG":"I am not the little priestess... Never mind. It was nice meeting you, too.","TWN":"不是小女巫……沒事，我也很開心。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"다음에 또 뵐 수 있는 날이 있었으면 좋겠네요.","JPN":"また会えるといいですね。","ENG":"I hope we meet again.","TWN":"希望下次還有機會見面。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유! 이것 봐! 롤러코스터야!","JPN":"千冬！　これを見て！　ジェットコースターよ！","ENG":"Chifuyu! Look at this! It is a rollercoaster!","TWN":"千冬！你看！是雲霄飛車！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"}}}},{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"당주님. 인파가 많은 데서 뛰시면 안 됩니다.","JPN":"当主。人ごみの中で走ってはいけません。","ENG":"My lady, you should not run in such a crowded area.","TWN":"堂主，不要在人多的地方跑來跑去。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"하지만 지금이 아니면 언제 이렇게 놀아보겠어? 사나에도 이번 기회에 신나게 놀고 오라고 했잖아.","JPN":"でも、今でなければいつ遊べるかわからないわ。早苗もこの機会に思い切り遊んで来いって言ったじゃない。","ENG":"But, when else will I be able to run around like this? Sanae also told me to have fun, you know.","TWN":"可是現在不玩的話，什麼時候才要玩呢？早苗不是也說要我們趁這個機會好好玩嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"그건…… 그렇습니다만……","JPN":"それは……そうですが……","ENG":"That's... correct, but...","TWN":"話…是沒錯…"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"같이 롤러코스터 타볼래? 치후유는 롤러코스터 타본 적 없지?","JPN":"一緒にジェットコースターに乗ってみる？　千冬はジェットコースターに乗ってみたことないわよね？","ENG":"Do you want to ride the rollercoaster together? You have never been on one, have you?","TWN":"要一起坐雲霄飛車嗎？千冬你也沒坐過吧？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"롤러코스터라…… 이번 기회에 당주님과 함께 즐기는 것도 괜찮겠군요.","JPN":"ジェットコースターですか……この機会に当主と一緒に楽しむのも悪くないですね。","ENG":"A rollercoaster... I guess it would be fine to enjoy my time with you, my lady.","TWN":"雲霄飛車嗎……趁著這次機會和堂主一起玩好像也不錯。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"그럼 타보자. 치후유. 자, 잠깐! 나 키 제한에 걸리는 건 아니겠지?","JPN":"じゃあ、乗ってみよう。千冬。あ、待って！　私、身長制限で乗れないなんてことないわよね？","ENG":"Let us get on, Chifuyu. W-wait! Do you think I will not meet the ride height?","TWN":"那就坐吧，千冬。等等！我應該不會因為太矮不能搭吧？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"후후, 다행히 제한에는 걸리지 않네요. 가시죠.","JPN":"ふふ、幸い制限よりは高かったようですね。行きましょう。","ENG":"Hehe. Fortunately, you're taller than the minimum. Let us keep going.","TWN":"呵呵，幸好沒有。走吧。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"후아! 역시 바람의 흐름을 느끼는 건 짜릿하구나.","JPN":"ふわあ！　やっぱり風の流れを感じるのってスカッとするわね。","ENG":"Huah! It is thrilling to feel the wind against your skin.","TWN":"呼！感受風的流動真是刺激。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"중력이 몸을 짓누르는 그 감각도 나쁘지 않았어.","JPN":"重力に体を押される感覚も悪くなかったわ。","ENG":"I also liked the feeling of gravity pressing on my body.","TWN":"重力壓迫身體的感覺也不錯。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"익스트림 스포츠. 최고야!","JPN":"エクストリームスポーツ、最高！","ENG":"An extreme sport. How fun!","TWN":"極限運動，好好玩！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"}}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유! 너도 재밌었지? 한 번 더 탈까?","JPN":"千冬！　どう、楽しかった？　もう一回乗ろうか？","ENG":"Chifuyu, you had fun too, right? Shall we go again?","TWN":"千冬！你也覺得很好玩吧？要不要再坐一次？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유?","JPN":"千冬？","ENG":"Chifuyu?","TWN":"千冬？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"속이……","JPN":"気分が……","ENG":"I'm feeling...","TWN":"我的胃……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"롤러코스터는…… 정말 무서운 기구이군요.","JPN":"ジェットコースターというのは……実に恐ろしい乗り物ですね。","ENG":"The rollercoaster... is a terrifying device.","TWN":"雲霄飛車……真是恐怖的東西。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"앞으로도 더 정진해야겠습니다.","JPN":"もっと精進しないといけません。","ENG":"I will have to train harder.","TWN":"看來我需要更多訓練。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"여기, 물 좀 마셔.","JPN":"はい、お水。","ENG":"Here, drink some water.","TWN":"給你，喝點水。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"감사합니다. 당주님.","JPN":"ありがとうございます、当主。","ENG":"Thank you, my lady.","TWN":"謝謝堂主。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"즐거워 보이셔서 다행입니다.","JPN":"楽しそうで何よりです。","ENG":"I am glad you seem to be enjoying yourself.","TWN":"看到堂主玩得這麼開心就好。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"응? 재밌으려고 온 거니까. 당연하지.","JPN":"うん？　楽しむために来たんだから、当たり前よ。","ENG":"Hmm? Well, we came here to have fun, did we not?","TWN":"嗯？我們是來玩的呀，當然開心囉。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"이 언니도 오랜만에 당주의 짐을 내려놓고 부담 없이 노는 중인걸?","JPN":"私も久しぶりに当主の任から解放されて、何の気兼ねもなく遊んでいるわ。","ENG":"I have let go of my duties as the head of our family and I am having fun.","TWN":"姊姊我也已經好久沒放下堂主的責任盡情地玩樂。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"그러니까 치후유도 이 언니의 장단에 맞춰줘야 해.","JPN":"だから千冬も姉さんに合わせてちょうだい。","ENG":"So, you should do the same.","TWN":"所以千冬也要配合姊姊的節奏。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"네. 저 역시 당주님 곁을 그림자처럼……","JPN":"はい。私もまた当主のそばで影のように……","ENG":"Of course. I shall stay close and protect you, my lady–","TWN":"是，我會像影子一樣陪在堂主身邊……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"당주가 아니라 언니! 그리고 치후유도 부담 없이 놀았으면 좋겠어.","JPN":"当主じゃなくて、姉さん！　それに、千冬にも何の気兼ねもなく遊んでほしいの。","ENG":"No, not lady! I am just your sister today. And I want you to have some fun as well.","TWN":"我不是堂主，是姊姊！而且我希望千冬也能夠放開地玩。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"알겠습니다. 그럼, 저기 회전 목마나 관람차도 같이 타보는 게 어떻습니까?","JPN":"わかりました。それでは、あそこのメリーゴーランドや観覧車にも一緒に乗ってくれませんか？","ENG":"Understood. Then, would you like to go on the merry-go-round? Or that Ferris wheel?","TWN":"好的。那我們一起去坐旋轉木馬和摩天輪好嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"회전목마를 즐기는 치후유의 모습……여기 보고 살짝만 웃어줄래?","JPN":"メリーゴーランドを楽しむ千冬の姿……こっち見て、ちょっとだけ笑ってくれる？","ENG":"Chifuyu enjoying the merry-go-round... Can you look this way and smile?","TWN":"千冬享受搭旋轉木馬的模樣……看我這邊，笑一下。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"이렇게 웃으면…… 될까요?","JPN":"こんな風に笑えば……いいのでしょうか？","ENG":"Smile...? Like this?","TWN":"這樣…笑嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"후후후. 좋아. 살짝 어색하게 올라간 입꼬리의 치후유도 좋은걸?","JPN":"ふふふ、いいわよ。ちょっとぎこちなく微笑む千冬もいいね。","ENG":"Hehehe. Yes. I like this awkwardly smiling Chifuyu.","TWN":"呵呵呵，不錯。僵硬地嘴角上揚的千冬也很可愛。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"하지만 좀 더 자연스러운 모습이 필요해……","JPN":"でももうちょっと自然さが必要よね……","ENG":"But I would like something that looks a bit more natural...","TWN":"但我想要更自然一點的表情……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"자신 있게 한쪽 팔을 올려볼래? 개선장군처럼 말이야.","JPN":"堂々とした感じで片手を上げてみようか？　凱旋将軍みたいに。","ENG":"Could you raise one arm with confidence? Like a general returning from battle with good news.","TWN":"你可以很有自信地舉起一隻手嗎？像凱旋將軍那樣。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"이, 이렇게 말입니까?","JPN":"こ、こうですか？","ENG":"L-like this?","TWN":"這，這樣可以嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"응.응. 좋아.","JPN":"うん、うん。いいわ。","ENG":"Yes, yes. Good.","TWN":"嗯嗯，不錯。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"회전목마 위의 개선장군 치후유라. 좋은 사진이야.","JPN":"メリーゴーランド上の凱旋将軍、千冬。よく撮れたわ。","ENG":"A victorious general atop a merry-go-round. What a great picture.","TWN":"旋轉木馬上的凱旋將軍，千冬。很棒的照片喔。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"이걸 크게 인화해서 방 액자에 걸어 둬야겠어.","JPN":"これを大きく印刷して部屋に飾るの。","ENG":"I will have this printed on a big canvas to frame it in my room.","TWN":"我要把這張照片放大，掛在房間裡。"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"사나에한테도 보여줘야지. 어떻게 생각해, 치후유?","JPN":"早苗にも見せて。どう思う？　千冬。","ENG":"I should show this to Sanae too. What do you think, Chifuyu?","TWN":"還要拿給早苗看。千冬，你覺得怎麼樣？"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"저, 저는…… 좀…… 부끄럽……","JPN":"わ、私は……少し……恥ずか……","ENG":"I-I... feel embarass–","TWN":"我，我有點……害羞……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"아, 관람차야! 치후유, 얼른 가자!","JPN":"あ、観覧車だよ！　千冬、早く行こう！","ENG":"Oh, the Ferris wheel! Chifuyu, make haste!","TWN":"哇，是摩天輪！千冬快來！"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};